ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?mx WHERE { ?x a :BaggageLimits ; p:BagWeightLimit ?w ; p:BagPieceLimit ?pc . BIND(IF(xsd:double(?w) > xsd:double(?pc), ?w, ?pc) AS ?mx) } }
  component: { SELECT (MAX(?bagweightlimit_a) AS ?agg) WHERE {
  ?baggagelimits a :BaggageLimits .
  ?baggagelimits p:BagWeightLimit ?bagweightlimit_a .
} }
  component_2: { SELECT (MAX(?bagpiecelimit_a) AS ?agg) WHERE {
  ?baggagelimits a :BaggageLimits .
  ?baggagelimits p:BagPieceLimit ?bagpiecelimit_a .
} }
}
